function migrate(address newL2TargetDispenser) external {
    if (_locked > 1) { revert ReentrancyGuard(); }
    _locked = 2;
    if (msg.sender != owner) { revert OwnerOnly(msg.sender, owner); }
    if (paused == 1) { revert Unpaused(); }
    if (newL2TargetDispenser.code.length == 0) { revert WrongAccount(newL2TargetDispenser); }
    if (newL2TargetDispenser == address(this)) { revert WrongAccount(address(this)); }
    uint256 amount = IToken(olas).balanceOf(address(this));
    if (amount > 0) {
        bool success = IToken(olas).transfer(newL2TargetDispenser, amount);
        if (!success) { revert TransferFailed(olas, address(this), newL2TargetDispenser, amount); }
    }
    owner = address(0);
    emit Migrated(msg.sender, newL2TargetDispenser, amount);
    // _locked is now set to 2 for good
}

function drain() external returns (uint256 amount) {
    if (_locked > 1) { revert ReentrancyGuard(); }
    _locked = 2;
    if (msg.sender != owner) { revert OwnerOnly(msg.sender, owner); }
    amount = address(this).balance;
    if (amount == 0) { revert ZeroValue(); }
    (bool success, ) = msg.sender.call{value: amount}("");
    if (!success) { revert TransferFailed(address(0), address(this), msg.sender, amount); }
    emit Drain(msg.sender, amount);
    _locked = 1;
}

receive() external payable {
    if (owner == address(0)) {
        revert TransferFailed(address(0), msg.sender, address(this), msg.value);
    }
    emit FundsReceived(msg.sender, msg.value);
}
